module adder_32bit(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

wire [32:1] C;
wire [32:1] P;
wire [32:1] G;

assign P[32:1] = A[32:1] ^ B[32:1];
assign G[32:1] = A[32:1] & B[32:1];

assign C[1] = P[1] & C[0];
generate
    genvar i;
    for (i = 2; i <= 32; i = i + 1) begin
        assign C[i] = (P[i] & C[i-1]) | G[i];
    end
endgenerate

assign S[32:1] = P[32:1] ^ {C[32:1], 1'b0};
assign C32 = C[32];

endmodule
